solution_code:
#include <iostream>
#include <string>

struct Settings
{
    std::string label{ "General" };
    int volume{ 50 };
};

int main()
{
    int n{};
    std::cin >> n;

    for (int i = 0; i < n; ++i)
    {
        std::string token;
        std::cin >> token;

        if (token == "default")
        {
            Settings s{};
            std::cout << s.label << ": volume=" << s.volume << '\n';
        }
        else
        {
            int vol{};
            std::cin >> vol;
            Settings s{ token, vol };
            std::cout << s.label << ": volume=" << s.volume << '\n';
        }
    }

    return 0;
}

